      {id:'heat',name:'30-day',render:function(d){ var heat='<div class="heat">'+HEAT30.map(function(o){return '<span style="opacity:'+o+'"></span>';}).join('')+'</div>'; if(!d) return heat; return heat+'<div class="sub" style="margin-top:9px;">Longest streak 6 days · 22 of 30 days active</div>'; }},
      {id:'score',name:'Score',render:function(d){ if(!d) return ring(84,{label:'weekly consistency score'}); return ring(84,{label:'weekly consistency score'})+gTable(['Pillar','Pts','Max'],[['Meals','28','30'],['Workouts','30','30'],['Steps','26','40']]); }}
