  toggleHoursTime(key){ this.setState({ hoursTimeOpen: this.state.hoursTimeOpen===key? null:key }); }
  setHoursTime(dayIdx, field, h, min, ap){ this.orgHours[dayIdx][field]=h+':'+String(min).padStart(2,'0')+' '+ap; this.forceUpdate(); }
  hoursValid(i){ const d=this.orgHours[i]; if(d.closed) return true; return this.parseTime(d.open) < this.parseTime(d.close); }
  // ---- copy hours
  openCopyHours(){ this.setState({ copyHoursOpen:true, copyHoursTargets:{} }); }
  closeCopyHours(){ this.setState({ copyHoursOpen:false }); }
  toggleCopyTarget(i){ const t={...this.state.copyHoursTargets}; if(t[i]) delete t[i]; else t[i]=true; this.setState({ copyHoursTargets:t }); }
  applyCopyHours(){ const src=this.orgHours[0]; Object.keys(this.state.copyHoursTargets).forEach(i=>{ const d=this.orgHours[+i]; d.open=src.open; d.close=src.close; d.closed=src.closed; }); const n=Object.keys(this.state.copyHoursTargets).length; this.setState({ copyHoursOpen:false }); this.toastMsg('Copied Monday\\u2019s hours to '+n+' day'+(n===1?'':'s')); }
  // ---- holidays
  overrideHoliday(id){ const h=this.holidays.find(x=>x.id===id); h.type = h.type==='observe_open'? 'default_closed' : 'observe_open'; this.forceUpdate(); this.toastMsg(h.type==='observe_open'? '"'+h.label+'" \\u2014 now Observe Open (scheduling allowed)' : '"'+h.label+'" \\u2014 back to Closed'); }
  openHolidayModal(id){ if(id){ const h=this.holidays.find(x=>x.id===id); this.setState({ holidayModal:'edit', holidayDraft:{...h} }); } else { this.setState({ holidayModal:'add', holidayDraft:{ id:null, date:'', label:'', type:'custom_closed', source:'custom' } }); } }
  closeHolidayModal(){ this.setState({ holidayModal:null, holidayDraft:null }); }
  setHolidayField(f,v){ this.setState({ holidayDraft:{...this.state.holidayDraft, [f]:v} }); }
  saveHoliday(){ const d=this.state.holidayDraft; if(!d.date || !d.label.trim()){ this.toastMsg('Date and label are required'); return; } if(d.id){ const h=this.holidays.find(x=>x.id===d.id); Object.assign(h,d); this.toastMsg('Holiday updated'); } else { this.holidays.push({...d, id:'h'+Date.now(), source:'custom'}); this.toastMsg('Custom holiday added'); } this.holidays.sort((a,b)=>a.date.localeCompare(b.date)); this.setState({ holidayModal:null, holidayDraft:null }); }
