  mkBlk(exName, sets, reps, weight, cat, src){
    const ex=this.exercises.find(e=>e.name===exName);
    const supports = ex? {...ex.metric} : {sets:true,reps:true,weight:true,duration:false,distance:false,calories:false};
    const values={sets:'',reps:'',weight:'',duration:'',distance:'',calories:'',rest:90};
    if(supports.sets) values.sets=sets; if(supports.reps) values.reps=reps;
    if(supports.weight) values.weight=weight; if(supports.duration&&!supports.weight) values.duration=reps;
    return { id:'blk_'+Math.random().toString(36).slice(2,8), exId:ex?ex.id:null, name:exName, cat:cat||'strength', supports, values, notes:'', source:src||'agent_programmed', collapsed:true };
  }
  // build progressed weekly content from per-day exercise themes
  seedContent(themes, weeks, readyWeeks){
    const content={};
    Object.keys(themes).forEach(dow=>{
      themes[dow].forEach((t,exIdx)=>{}); // noop
    });
    for(let w=0; w<weeks; w++){
      Object.keys(themes).forEach(dow=>{
        const key='w'+w+'_'+dow;
        if(w>=readyWeeks){ content[key]=[]; return; } // empty future weeks coach extends
        content[key]=themes[dow].map(t=>{
          const baseW=t[3]; const prog=baseW? Math.round(baseW*(1+0.05*w)) : '';
          return this.mkBlk(t[0], t[1], t[2], prog, t[4], 'agent_programmed');
        });
      });
    }
    return content;
  }

